class ConfigParserWithComments(configparser.ConfigParser):
    """ConfigParser that can store and preserve comments."""
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._section_comments = {}
        self._option_comments = {}

    def add_section_comment(self, section, comment):
        self._section_comments.setdefault(section, []).append(comment)

    def add_option_comment(self, section, option, comment):
        self._option_comments.setdefault((section, option), []).append(comment)

def serialize(config, path):
    """Write config to an INI file, preserving comments and handling special chars."""
    # First write using standard method to get proper escaping
    buf = io.StringIO()
    config.write(buf)
    content = buf.getvalue()

    # Split into lines, keeping track of sections
    lines = content.splitlines(True)

    has_section_comments = hasattr(config, '_section_comments')
    has_option_comments = hasattr(config, '_option_comments')

    with open(path, 'w', encoding='utf-8') as f:
        current_section = None
        for line in lines:
            stripped = line.strip()

            # Detect section headers
            if stripped.startswith('[') and stripped.endswith(']') and not stripped.startswith('[['):
                section_name = stripped[1:-1].strip()
                current_section = section_name
                # Write section comments
                if has_section_comments and section_name in config._section_comments:
                    for comment in config._section_comments[section_name]:
                        f.write(comment.rstrip('\n') + '\n')
                f.write(line)
            elif current_section and ('=' in stripped or ':' in stripped) and not stripped.startswith('#'):
                # Option line - write option comments before it
                sep = '=' if '=' in stripped else ':'
                option_name = stripped.split(sep, 1)[0].strip()
                if has_option_comments:
                    key = (current_section, option_name)
                    if key in config._option_comments:
                        for comment in config._option_comments[key]:
                            f.write(comment.rstrip('\n') + '\n')
                f.write(line)
            else:
                f.write(line)

